// TestRegression_MiddlewareIntegration tests that the middleware doesn't currently
// extract browser-based tokens or support server-level auth skipping.
func TestRegression_MiddlewareIntegration(t *testing.T) {
	t.Run("CookieTokenExtraction", func(t *testing.T) {
		// Issue 1: Cookie tokens are not extracted
		req := httptest.NewRequest("GET", "http://localhost/api/flags", nil)
		req.AddCookie(&http.Cookie{
			Name:  "flipt_client_token",
			Value: "test_token",
		})

		// ForwardCookies should properly convert this to gRPC metadata
		// that the gRPC middleware can process
		md := ForwardCookies_Buggy(context.Background(), req)

		// Verify the bug exists: metadata is not properly structured
		// for the gRPC middleware to extract tokens from cookies
		if len(md) > 0 {
			// Metadata was created, but is it in the right format?
			cookie := md.Get("grpcgateway-cookie")
			if len(cookie) == 0 {
				t.Error("REGRESSION: Cookies not forwarded to grpcgateway-cookie metadata key")
			}
		} else {
			t.Error("REGRESSION: ForwardCookies returned empty metadata")
		}
	})

	t.Run("ServerAuthSkipNotConfigured", func(t *testing.T) {
		// Issue 2: No mechanism to skip authentication for specific servers
		// The public server implements SkipsAuthenticationServer but
		// is never registered with WithServerSkipsAuthentication

		// There should be a way to configure servers to skip auth, but:
		// 1. Public servers are not registered with this option
		// 2. So the middleware can't know to skip them
		// 3. They are still forced through authentication

		// Expected: Public authentication methods don't require auth
		// Actual: All methods require auth because public server is not configured

		t.Log("Public server implements SkipsAuthenticationServer")
		t.Log("But WithServerSkipsAuthentication is never called")
		t.Log("This means public methods are incorrectly protected by auth middleware")
	})
}

